import { Buff }   from '@cmdcode/buff'
import { Script } from '@scure/btc-signer'
import { Assert } from '@/util/index.js'

import { Network, ScriptData, TxData }   from '@scrow/tapscript'
import { create_addr, P2TR, parse_addr } from '@scrow/tapscript/address'
import { encode_tapscript, tap_pubkey }  from '@scrow/tapscript/tapkey'

import {
  decode_script,
  encode_script,
  parse_script
} from '@scrow/tapscript/script'

import {
  create_vin,
  parse_tx,
  parse_txid,
  parse_txsize,
  encode_tx as scrow_encode_tx,
  decode_tx as scrow_decode_tx
} from '@scrow/tapscript/tx'

import type { BaseUtxo, OrdUtxo } from '@/types/index.js'

import CONST from '@/const.js'

export function create_address (
  script  : string,
  network : Network = 'regtest'
) {
  return create_addr(script, network)
}

export function create_sats_txin (utxo : BaseUtxo) {
  const { txid, vout, value, script } = utxo
  return create_vin({ txid, vout, prevout: { value, scriptPubKey: script } })
}

export function create_ord_txin (utxo : OrdUtxo) {
  const { txid, vout, value: postage, script } = utxo
  return create_vin({ txid, vout, prevout: { value: postage, scriptPubKey: script } })
}

export function get_block_seq_val (timer : number) : number{
  const BLOCK_TIME = CONST.BLOCK_DURATION
  const time_delay = Math.max(timer, BLOCK_TIME)
  return Math.ceil(time_delay / BLOCK_TIME)
}

/**
 * Extract a BaseUtxo object from a transaction output.
 * @param tx   : The transaction data as an object or hex string.
 * @param vout : The index of the transaction output.
 * @returns
 */
export function extract_utxo (
  tx   : string | TxData,
  vout : number
) : BaseUtxo {
  const txdata  = parse_tx(tx)
  const txid    = parse_txid(txdata)
  const prevout = txdata.vout.at(vout)
  Assert.exists(prevout, 'tx output does not exist')
  const { value, scriptPubKey } = prevout
  const script = encode_script(scriptPubKey, false).hex
  return { script, txid, vout, value: Number(value) }
}

/**
 * Extract an OP_RETURN output script from a transaction.
 * @param tx : The transaction data as an object or hex string.
 * @returns
 */
export function extract_op_return (
  tx : string | TxData
) : string {
  const txdata = parse_tx(tx)
  const txout  = txdata.vout.at(-1)
  Assert.exists(txout,                       'tx output does not exist')
  Assert.ok(txout.value === CONST.BIGINT._0, 'tx data output is not zero value')
  const script = parse_script(txout.scriptPubKey)
  Assert.ok(script.asm[0] === 'OP_RETURN',   'output script does not start with OP_RETURN')
  return script.hex
}

export function get_txid (txdata : string | TxData) {
  return parse_txid(txdata)
}

export function get_txsize (txdata : string | TxData) {
  return parse_txsize(txdata)
}

export function get_vin_vsize(utxos : BaseUtxo[]) {
  let vsize = 0
  for (const utxo of utxos) {
    const ctx = parse_script_meta(utxo.script)
    vsize += get_txin_type_vsize(ctx.type)
  }
  return vsize
}

export function get_txin_type_vsize (type : string) {
  switch (type) {
    case 'p2sh':
      return CONST.TXSIZE.TXIN.P2SH
    case 'p2w-pkh':
      return CONST.TXSIZE.TXIN.P2WK
    case 'p2tr':
      return CONST.TXSIZE.TXIN.P2TR
    default:
      throw new Error('unsupported input type: ' + type)
  }
}

/**
 * Create a script-only taproot key from a tree of scripts.
 */
export function get_taproot_script_key (
  scripts : (string | Uint8Array)[],
  index   : number = 0,
  version : number = 0xc0
) : string {
  // Encode the entire script tree as tapleaves.
  const taptree = scripts.map(e => encode_tapscript(e, version))
  // Encode the redeem script (index 0) as a tapleaf.
  const tapleaf = taptree[index]
  // Get the context of the taproot tree and pubkey.
  const taproot_ctx = tap_pubkey(CONST.UNSPENDABLE_KEY, { taptree, tapleaf })
  // Return taproot key.
  return taproot_ctx.tapkey
}

export function create_tr_address (
  pubkey  : string, 
  network : Network
) {
  return P2TR.encode(pubkey, network)
}

export function encode_p2tr_pubkey (pubkey : string) : Uint8Array {
  return Script.encode([ 'OP_1', Buff.hex(pubkey) ])
}

export function encode_tx (txdata : TxData) : string {
  return scrow_encode_tx(txdata).hex
}

export function decode_tx (txhex : string) : TxData {
  return scrow_decode_tx(txhex)
}

export function parse_address (address : string) {
  return parse_addr(address)
}

export function parse_address_script (address : string) {
  // TODO: validate address here.
  return Buff.hex(parse_addr(address).hex)
}

export function parse_script_meta (script : ScriptData) {
  return parse_script(script)
}

export function parse_script_asm (script : ScriptData) {
  return parse_script(script).asm as string[]
}


export default {
  create_address,
  create_tr_address,
  create_ord_txin,
  create_sats_txin,
  extract_utxo,
  extract_op_return,
  get_block_seq_val,
  get_taproot_script_key,
  get_txid,
  get_txsize,
  get_txin_type_vsize,
  get_vin_vsize,
  encode_script : (script : (string | Uint8Array)[], varint = false) => encode_script(script, varint),
  decode_script,
  encode_p2tr_pubkey,
  encode_tx,
  decode_tx,
  parse_address,
  parse_address_script,
  parse_script_asm,
  parse_script_meta
}
