import {
  fetch_record_content,
  fetch_satpoint_content
} from './ordx.js'

import type {
  AccountRecord,
  ApiResponse,
  ExchangeRecord,
  GuardianRecord,
  Literal
} from '@/types/index.js'

import CONST  from '@/const.js' 
import Schema from '@/schema/index.js'

export async function fetch_account_record (
  ord_url    : string,
  identifier : string
) : Promise<ApiResponse<AccountRecord>> {
  const schema = Schema.oracle.record.acct_record
  return fetch_record_content<AccountRecord>(ord_url, identifier, schema)
}

export async function fetch_guardian_record (
  ord_url    : string,
  identifier : string
) : Promise<ApiResponse<GuardianRecord>> {
  const schema = Schema.oracle.record.host_record
  return fetch_record_content<GuardianRecord>(ord_url, identifier, schema)
}

export async function fetch_exchange_record (
  ord_url    : string,
  identifier : string
) : Promise<ApiResponse<ExchangeRecord>> {
  const schema = Schema.oracle.record.host_record
  return fetch_record_content<ExchangeRecord>(ord_url, identifier, schema)
}

export async function fetch_terms_record (
  ord_url : string,
  pointer : number,
  ival    : number = CONST.FETCH_IVAL
) : Promise<ApiResponse<Literal[]>> {
  const schema = Schema.oracle.record.val_arr
  return fetch_satpoint_content<Literal[]>(ord_url, pointer, { ival, schema })
}
