import { Assert, Fetch, OrdUtil, Resolve } from '@/util/index.js'

import { ApiResponse } from '../types/fetch.js'

import {
  InscriptionResponse,
  OrdOutputResponse,
  RuneResponse,
  SatResponse,
  OrdTxResponse,
  InscriptionChildResponse,
  SatIndexResponse,
  OrdAddressResponse
} from '../types/index.js'

export async function ord_fetch_tx (
  ord_url : string,
  txid    : string
) : Promise<ApiResponse<OrdTxResponse>> {
  Assert.is_hash(txid)
  const url = `${ord_url}/tx/${txid}`
  const opt = { headers: { Accept: 'application/json' } }
  return Fetch.json<OrdTxResponse>(url, opt)
}

