export async function ord_fetch_sat_identifier (
  ord_url : string,
  sat_ptr : number,
  index   : number = 0
) : Promise<ApiResponse<string | null>> {
  const url = `${ord_url}/r/sat/${sat_ptr}/at/${index}`
  const opt = { headers: { Accept: 'application/json' } }
  const res = await Fetch.json<SatIndexResponse>(url, opt)
  if (!res.ok) return res
  return Resolve.data(res.data.id)
}
