import { Assert, Fetch, Resolve } from '@/util/index.js'

import {
  ApiResponse,
  EsploraAddressData,
  EsploraAddressUtxo,
  EsploraTxData
} from '@/types/index.js'

/**
 * Fetches transaction details from an Esplora endpoint
 * @param esplora_url - Base URL of the Esplora API server
 * @param txid - Transaction hash to lookup
 * @returns Transaction data or error response
 */
export async function esplora_get_tx (
  esplora_url : string,
  txid        : string
) : Promise<ApiResponse<EsploraTxData>> {
  // Verify txid is a valid hash format
  Assert.is_hash(txid)
  const url = `${esplora_url}/tx/${txid}`
  return Fetch.json<EsploraTxData>(url)
}

/**
 * Fetches address information from an Esplora endpoint
 * @param esplora_url - Base URL of the Esplora API server
 * @param address - Bitcoin address to lookup
 * @returns Address data including balance and transaction counts
 */
export async function esplora_get_address_data (
  esplora_url : string,
  address     : string
) : Promise<ApiResponse<EsploraAddressData>> {
  const url = `${esplora_url}/address/${address}`
  return Fetch.json<EsploraAddressData>(url)
}

/**
 * Fetches UTXOs for a given address, optionally filtering by amount
 * @param esplora_url - Base URL of the Esplora API server
 * @param address - Bitcoin address to lookup UTXOs for
 * @param filter - Optional array of satoshi amounts to filter UTXOs by
 * @returns Array of UTXO data or error response
 */
export async function esplora_get_utxos (
  esplora_url : string,
  address     : string,
  filter?     : number[]
) : Promise<ApiResponse<EsploraAddressUtxo[]>> {
  const url = `${esplora_url}/address/${address}/utxo`
  const res = await Fetch.json<EsploraAddressUtxo[]>(url)
  
  if (!res.ok) return res
  
  // If filter array provided, only return UTXOs with matching amounts
  const utxos = (Array.isArray(filter))
    ? res.data.filter(e => filter.includes(e.value))
    : res.data
  return Resolve.data(utxos)
}

/**
 * Broadcasts a raw transaction to the network via Esplora
 * @param esplora_url - Base URL of the Esplora API server
 * @param txhex - Raw transaction hex to broadcast
 * @returns Transaction ID if successful, error response if failed
 */
export async function esplora_publish_tx (
  esplora_url : string,
  txhex       : string
) : Promise<ApiResponse<string>> {
  const url = `${esplora_url}/tx`
  const opt = { body: txhex, method: 'POST' }
  return Fetch.text(url, opt)
}
