/**
 * Postage Map
 */

/* ============ [ Types ] ============*/

export type PointerKeys = 
  'repo_liquidation_thold'  |
  'repo_reserve_pubkey'     |
  'repo_reserve_sats_min'   |
  'repo_liquid_tax_rate'    |
  'repo_subsidy_inc_rate'   |
  'repo_subsidy_inc_thold'  |
  'vault_sats_balance_min'  |
  'vault_unit_balance_min'  |
  'vault_collateral_min'    |
  'vault_internal_key'

export type PostageKeys = 'master'       | 'guard_hosts'  | 'guard_group'
                        | 'unit_account' | 'unit_reserve' | 'vault_terms'
                        | 'vault_point'  | 'oracle_hosts' | 'oracle_group'
                        | 'vault_token'  | 'repo_terms'   | 'repo_point'

/* ============ [ Maps ] ============*/

const POINTER_TYPES : Record<number, PointerKeys> = {
  10101 : 'repo_liquidation_thold',
  10102 : 'repo_reserve_pubkey',
  10103 : 'repo_reserve_sats_min',
  10104 : 'repo_liquid_tax_rate',
  10105 : 'repo_subsidy_inc_rate',
  10106 : 'repo_subsidy_inc_thold',
  10107 : 'vault_collateral_min',
  10108 : 'vault_internal_key',
  10109 : 'vault_sats_balance_min',
  10110 : 'vault_unit_balance_min'
} as const

const POSTAGE_TYPES : Record<number, PostageKeys> = {
  10001 : 'master',
  10002 : 'guard_hosts',
  10003 : 'guard_group',
  10004 : 'unit_account',
  10005 : 'unit_reserve',
  10006 : 'vault_terms',
  10007 : 'vault_point',
  10008 : 'oracle_hosts',
  10009 : 'oracle_group',
  10010 : 'repo_terms',
  10011 : 'repo_point',
} as const

/* ============ [ Exports ] ============*/

export namespace POINTER {
  export const KEYS     = Object.values(POINTER_TYPES)
  export const RANGE    = [ 10100, 10200 ]
  export const TYPES    = POINTER_TYPES
  export const GET_KEY  = (type : number)      => get_record_key(POINTER_TYPES, type)
  export const GET_TYPE = (key  : PointerKeys) => get_record_type(POINTER_TYPES, key)
}

export namespace POSTAGE {
  export const KEYS     = Object.values(POSTAGE_TYPES)
  export const RANGE    = [ 10001, 10100 ]
  export const TYPES    = POSTAGE_TYPES
  export const GET_KEY  = (type : number)      => get_record_key(POSTAGE_TYPES, type)
  export const GET_TYPE = (key  : PostageKeys) => get_record_type(POSTAGE_TYPES, key)
}

export default { POINTER, POSTAGE }

/* ============ [ Helpers ] ============*/

function get_record_key <T extends Record<number, string>> (
  map  : T,
  type : keyof T
) : string {
  const ent = map[type]
  if (typeof ent !== 'string') throw new Error('value does not exist for type: ' + String(type))
  return ent
}

function get_record_type <T extends Record<number, string>> (
  map : T,
  key : T[keyof T]
) : number {
  const ent = Object.entries(map).find(e => e[1] === key)
  if (ent === undefined) throw new Error('type does not exist for key: ' + key)
  return Number(ent[0])
}
