import { Buff }   from '@cmdcode/buff'
import { Assert } from '@/util/index.js'

import {
  create_vault_cleared_spend_script,
  create_vault_fund_conn_script,
  create_vault_locked_spend_script,
  create_vault_open_conn_script
} from './script.js'

import {
  BaseUtxo,
  VaultOpenCtx,
  PSBTBaseInput,
  VaultBaseCtx,
  VaultRepoCtx,
  VaultInput,
  LiquidVaultProfile
} from '@/types/index.js'

import CONST from '@/const.js'
import PSBT  from '@/util/psbt.js'

/**
 * Create a vault open connector input for a transaction.
 */
export function create_vault_open_conn_vin (
  vault_ctx  : VaultOpenCtx,
  vault_utxo : BaseUtxo
) : PSBTBaseInput {
  // Create a PSBT input for the connector utxo.
  const input   = PSBT.create.input(vault_utxo) as PSBTBaseInput
  // Create the bitcoin script for the connector utxo.
  const scripts = create_vault_open_conn_script(vault_ctx)
  // Create the tapleaf script for the connector utxo.
  const tapleaf = PSBT.create.tapscript(scripts, 0)
  // Return the PSBT input.
  return {
    ...input,
    tapLeafScript  : [ tapleaf ],
    tapInternalKey : Buff.hex(CONST.UNSPENDABLE_KEY)
  }
}

/**
 * Create a vault funding connector input for a transaction.
 */
export function create_vault_fund_conn_vin (
  vault_ctx : VaultBaseCtx,
  conn_utxo : BaseUtxo
) : PSBTBaseInput {
  // Unpack the vault data.
  const { guard_pubkey, vault_pubkey } = vault_ctx
  // Create a PSBT input for the connector utxo.
  const input   = PSBT.create.input(conn_utxo) as PSBTBaseInput
  // Create the bitcoin script for the connector utxo.
  const scripts = create_vault_fund_conn_script(guard_pubkey, vault_pubkey)
  // Return the PSBT input.
  return {
    ...input,
    tapLeafScript  : [ PSBT.create.tapscript(scripts, 0) ],
    tapInternalKey : Buff.hex(CONST.UNSPENDABLE_KEY)
  }
}

