/**
 * Create a locked vault spend input for a transaction.
 */
export function create_vault_locked_spend_vin (
  guard_pubkey : string,
  thold_hash   : string,
  vault_pubkey : string,
  vault_utxo   : BaseUtxo
) : PSBTBaseInput {
  // Create a PSBT input for the vault utxo.
  const input   = PSBT.create.input(vault_utxo) as PSBTBaseInput
  // Create the bitcoin script for the vault utxo.
  const scripts = create_vault_locked_spend_script(guard_pubkey, thold_hash, vault_pubkey)
  // Return the PSBT input.
  return {
    ...input,
    tapLeafScript  : [ PSBT.create.tapscript(scripts, 0) ],
    tapInternalKey : Buff.hex(CONST.UNSPENDABLE_KEY)
  }
}

/**
 * Create a vault spen input for a transaction.
 */
export function create_vault_spend_vin (
  vault_ctx : VaultBaseCtx & VaultInput
) : PSBTBaseInput {
  // Get the bitcoin script for the vault utxo.
  const { guard_pubkey, vault_quote, vault_balance, vault_pubkey, vault_utxo } = vault_ctx
  const thold_hash = vault_quote.thold_hash
  return (vault_balance > 0)
    ? create_vault_locked_spend_vin(guard_pubkey, thold_hash, vault_pubkey, vault_utxo)
    : create_vault_cleared_spend_vin(guard_pubkey, vault_pubkey, vault_utxo)
}

/**
 * Create a vault reposession input for a transaction.
 */
export function create_liquid_spend_vin (
  vault_ctx     : VaultRepoCtx,
  vault_profile : LiquidVaultProfile
) : PSBTBaseInput {
  // Unpack the liquid vault data.
  const { rdata, vault_pk, thold_key, utxo } = vault_profile
  // Assert that the vault is locked.
  Assert.ok(rdata.is_locked, 'liquid vault is not locked')
  // Get the hash-lock for the vault.
  const thold_hash = rdata.thold_hash
  // Create the bitcoin script for the vault utxo.
  const scripts = create_vault_locked_spend_script(vault_ctx.guard_pubkey, thold_hash, vault_pk)
  // Get the PSBT input utxo data.
  const input = PSBT.create.input(utxo) as PSBTBaseInput
  // Get the hash-lock PSBT input data.
  const hlock = PSBT.create.hashlock(thold_hash, thold_key)
  // Return the spending input with the hash-lock included.
  return {
    ...input,
    hash160        : [ hlock ],
    tapLeafScript  : [ PSBT.create.tapscript(scripts, 1) ],
    tapInternalKey : Buff.hex(CONST.UNSPENDABLE_KEY)
  }
}
