import { Fetch } from '@/util/fetch.js'

import type {
  ApiResponse,
  PriceQuote
} from '@/types/index.js'

export async function fetch_price_quote (
  exchange_url : string,
  thold_price  : number,
  quote_stamp? : number
) : Promise<ApiResponse<PriceQuote>> {
  const query = new URLSearchParams({ th: String(thold_price) })
  if (quote_stamp !== undefined) {
    query.append('ts', String(quote_stamp))
  }
  const url = `${exchange_url}/api/quote?` + query.toString()
  const opt : RequestInit = { method: 'GET' }
  return Fetch.json<PriceQuote>(url, opt)
}
