import { z }      from 'zod'
import { Assert } from './validate.js'

import type { SafeReturn } from '@/types/index.js'

export function now () {
  return Math.floor(Date.now() / 1000)
}

export async function sleep (ms : number = 1000) {
  return new Promise(res => setTimeout(res, ms))
}

export function get_map_value (
  terms : Map<string, any>,
  key   : string,
  idx   : number = 0
) {
  const value = terms.get(key)?.at(idx)
  Assert.exists(value, 'value is null or undefined: ' + key)
  return value
}

export function round_to_fixed (
  float_value : number,
  precision   : number
) {
  return parseFloat(float_value.toFixed(precision))
}

export function parse_schema <S extends z.ZodTypeAny> (
  input  : unknown,
  schema : S,
  error? : string
) : z.infer<S> {
  try {
    return schema.parse(input)
  } catch (err) {
    console.error(err)
    if (typeof error === 'string') {
      throw new Error(error)
    } else {
      throw err
    }
  }
}

export function parse_error (err : unknown) : string {
  if (err instanceof Error) {
    return err.message
  } else if (typeof err === 'string') {
    return err
  } else {
    return String(err)
  }
}

export async function resolver <T> (
  fn      : Function,
  timeout : number
) : Promise<T> {
  return new Promise((resolve, reject) => {
    const timer = setTimeout(() => reject('timeout'), timeout)
    fn().then((res : T) => {
      clearTimeout(timer)
      resolve(res)
    })
  })
}

export async function safe_exec <T> (
  fn : () => T | Promise<T>
) : Promise<SafeReturn<T>> {
  try {
    return { ok: true, data: await fn() }
  } catch (err) {
    return { ok: false, err }
  }
}

export function normalize_obj <
  T extends Record<keyof T, any>
> (obj : T) : T {
  if (obj instanceof Map || Array.isArray(obj) || typeof obj !== 'object') {
    return obj
  } else {
    return Object.keys(obj)
      .sort()
      .filter(([ _, value ]) => value !== undefined)
      .reduce<Record<string, any>>((sorted, key) => {
        sorted[key] = obj[key as keyof T]
        return sorted
      }, {}) as T
  }
}

export function get_record_key <T extends Record<number, string>> (
  map  : T,
  type : keyof T
) : string {
  const ent = Object.entries(map).find(e => e[0] === type)
  if (ent === undefined) throw new Error('value does not exist for type: ' + String(type))
  return ent[1]
}

export function get_record_type <T extends Record<number, string>> (
  map : T,
  key : T[keyof T]
) : number {
  const ent = Object.entries(map).find(e => e[1] === key)
  if (ent === undefined) throw new Error('type does not exist for key: ' + key)
  return Number(ent[0])
}
