import {
  create_change_out,
  create_vault_return,
  create_vault_spend_out,
  create_vault_spend_vin,
  get_contract_input,
  get_vault_input,
  get_vault_return_data
} from '@/module/vault/lib/index.js'

import {
  VaultWithdrawCtx,
  VaultWithdrawRequest,
  VaultWithdrawConfig,
  PriceQuote,
  ProtocolProfile,
  VaultProfile,
  VaultTxQuote
} from '@/types/index.js'

import CONST  from '@/const.js'
import PSBT   from '@/util/psbt.js'
import Schema from '@/schema/index.js'
import TX     from '@/util/tx.js'

const VAULT_VIN_IDX = CONST.TXMAP.withdraw.vault_tx.vin.vault

/**
 * Create a context object for a Vault Withdraw action.
 * 
 * @param contract_ctx  Context object from the on-chain contract.
 * @param exchange_data Price data provided by the oracle.
 * @param vault_config  User-provided config for updating the vault.
 * @param vault_prevout Prevout object from the current vault utxo.
 * @returns A VaultWithdrawCtx object.
 */
export function create_vault_withdraw_ctx (
  price_quote   : PriceQuote,
  proto_profile : ProtocolProfile,
  vault_profile : VaultProfile,
  req_config    : VaultWithdrawConfig
) : VaultWithdrawCtx {
  return {
    ...req_config,
    ...get_contract_input(proto_profile),
    ...get_vault_input(vault_profile),
    vault_quote  : price_quote,
    vault_action : 'w'
  }
}

/**
 * Create a vault withdraw PSBT.
 */
export function create_vault_withdraw_psbt (
  vault_ctx : VaultWithdrawCtx
) {
  // Unpack the vault context object.
  const { change_amount, vault_balance, vault_utxo } = vault_ctx
  // Get the cost for the withdraw tx.
  const tx_quote = get_vault_withdraw_quote(vault_ctx)
  // Compute a new vault output amount.
  const vault_amount = vault_utxo.value - tx_quote.total_cost
  // Get the return data for the repo transaction.
  const return_data = get_vault_return_data(vault_ctx, vault_balance)
  // Create a PSBT template.
  const pdata = PSBT.create.psbt({ allowUnknownOutputs: true })
  // Add the vault utxo output.
  pdata.addOutput(create_vault_spend_out(vault_ctx, vault_balance, vault_amount))
  // Add the wallet change output.
  pdata.addOutput(create_change_out(vault_ctx, change_amount))
  // Add the vault data output.
  pdata.addOutput(create_vault_return(return_data))
  // Add the vault connector input.
  pdata.addInput(create_vault_spend_vin(vault_ctx))
  // Return the data encoded in PSBT format.
  return PSBT.encode(pdata)
}

/**
 * Create a network request for the vault withdraw action.
 */
export function create_vault_withdraw_req (
  vault_ctx  : VaultWithdrawCtx,
  vault_psbt : string
) : VaultWithdrawRequest {
  const vault_txhex = PSBT.get.txhex(vault_psbt)
  const vault_txid  = TX.get_txid(vault_txhex)
  // Extract the vault update input.
  const vault_input = PSBT.extract.script_vin(vault_psbt, VAULT_VIN_IDX)
  // Define the schema for the request.
  const schema = Schema.vault.req.withdraw_req
  // Return a request object.
  return schema.parse({ ...vault_ctx, vault_input, vault_psbt, vault_txhex, vault_txid })
}

/**
 * Calculate the total (in sats) required to
 * fund a withdraw transaction.
 */
export function get_vault_withdraw_quote (
  vault_config : VaultWithdrawConfig
) : VaultTxQuote {
  const { change_amount, tx_feerate } = vault_config
  const total_size = CONST.TXSIZE.ACTION.VAULT_WITHDRAW
  const tx_cost    = total_size * tx_feerate
  const total_cost = change_amount + tx_cost
  return { tx_vsize: total_size, tx_cost, total_cost }
}

export default {
  create_ctx  : create_vault_withdraw_ctx,
  create_psbt : create_vault_withdraw_psbt,
  create_req  : create_vault_withdraw_req,
  get_quote   : get_vault_withdraw_quote
}
