import { parse_vault_prevout } from '../lib/vault.js'

import {
  fetch_record_content,
  fetch_record_id
} from './ordx.js'

import {
  ord_fetch_inscription,
  ord_fetch_outpoint,
  ord_fetch_tx
} from './ord.js'

import {
  parse_outpoint_sat,
  parse_outpoint_utxo
} from '../lib/ord.js'

import {
  Assert,
  OrdUtil,
  Resolve,
  sleep
} from '@/util/index.js'

import {
  VaultRecord,
  type ApiResponse,
  type VaultPrevout,
  type VaultProfile,
  type VaultToken,
  type VaultTokenData
} from '@/types/index.js'

import CONST    from '@/const.js'
import Schema   from '@/schema/index.js'

const DEFAULT_IVAL = CONST.FETCH_IVAL

/**
 * Fetch a vault token for the provided outpoint.
 * 
 * @param ord_url  : The host URL for the ord server.
 * @param outpoint : The outpoint for the vault token.
 * @param interval : Delay consecutive fetching by an interval (in ms).
 * @returns A response object containing the vault token.
 */
export async function fetch_vault_token (
  ord_url  : string,
  outpoint : string,
  ival     : number = DEFAULT_IVAL
) : Promise<ApiResponse<VaultToken>> {
  OrdUtil.assert_outpoint(outpoint)
  const res1 = await ord_fetch_outpoint(ord_url, outpoint)
  if (!res1.ok) return res1
  const ptr  = parse_outpoint_sat(res1.data)
  Assert.exists(ptr, 'sat pointer is null')
  await sleep(ival)
  const res2 = await fetch_record_id(ord_url, ptr)
  if (!res2.ok) return res2
  const tkn_id = res2.data
  await sleep(ival)
  const schema = Schema.vault.base.token_data
  const res3   = await fetch_record_content<VaultTokenData>(ord_url, tkn_id, schema)
  if (!res3.ok) return res3
  const revision = res3.data.rev
  let   vid      = tkn_id.slice(0, -1) + 1
  if (revision > 0) {
    await sleep(ival)
    const idx = (-1 * revision) - 1
    const res = await fetch_record_id(ord_url, ptr, idx)
    if (!res.ok) return res
    vid = res.data.slice(0, -1) + 1
  }
  const data = res3.data
  const utxo = parse_outpoint_utxo(outpoint, res1.data)
  return Resolve.data({ data, ptr, utxo, vid })
}

export async function fetch_vault_prevout (
  ord_url : string,
  txid    : string
) : Promise<ApiResponse<VaultPrevout>> {
  const res = await ord_fetch_tx(ord_url, txid)
  //
  if (!res.ok) return res
  //
  const prevout = parse_vault_prevout(res.data)
  //
  return Resolve.data(prevout)
}

/**
 * Fetch the latest vault profile data for the provided outpoint.
 * 
 * @param ord_url  : The host URL for the ord server.
 * @param outpoint : The outpoint to fetch from.
 * @param interval : Delay consecutive fetching by an interval (in ms).
 */
export async function fetch_vault_profile (
  ord_url  : string,
  token    : VaultToken,
  interval : number = DEFAULT_IVAL
) : Promise<ApiResponse<VaultProfile>> {
  // Fetch the vault inscription data.
  const res1 = await ord_fetch_inscription(ord_url, token.vid)
  // If response fails, return early.
  if (!res1.ok) return res1
  // Parse the satpoint for the vault.
  const satpoint = OrdUtil.parse_satpoint(res1.data.satpoint)
  // Get the parent identifier for the vault.
  const acct_id  = res1.data.parents.at(0)
  // Assert the parent identifier exists.
  Assert.exists(acct_id, 'vault record not linked to an account')
  // Wait the specified interval.
  await sleep(interval)
  // Define a schema to validate the vault record.
  const schema = Schema.oracle.vault.record
  // Fetch the vault record data.
  const res2 = await fetch_record_content<VaultRecord>(ord_url, token.vid, schema)
  // If response fails, return early.
  if (!res2.ok) return res2
  // Extract the vault data from the vault record.
  const { gpk, mid, vpk } = res2.data
  // Wait the specified interval.
  await sleep(interval)
  // Fetch latest prevout for the vault.
  const res3 = await fetch_vault_prevout(ord_url, satpoint[0])
  // If response fails, return early.
  if (!res3.ok) return res3
  // Return completed vault data.
  return Resolve.data({
    ...res3.data,
    acct_id,
    guard_pk  : gpk,
    master_id : mid,
    vault_pk  : vpk
  })
}
